import { VertexAI } from "@google-cloud/vertexai";

interface VideoGenerationOptions {
  prompt: string;
  duration?: number;
  resolution?: string;
  aspectRatio?: string;
}

interface VideoGenerationResult {
  videoUrl: string;
  operationName: string;
}

async function getVideoOperation(
  vertexAI: VertexAI,
  operationName: string,
  location: string = "us-central1"
) {
  const [operation] = await vertexAI.operationsClient.getOperation({
    name: operationName,
  });
  return operation;
}

export async function generateVideo(
  prompt: string,
  options: VideoGenerationOptions = {}
): Promise<string> {
  const {
    duration = 8,
    resolution = "1080p",
    aspectRatio = "16:9",
  } = options;

  let projectId = process.env.GOOGLE_PROJECT_ID;
  const location = process.env.GOOGLE_LOCATION || "us-central1";
  const apiKey = process.env.GOOGLE_API_KEY;

  // 如果没有配置 projectId，尝试从环境变量或 gcloud 获取
  if (!projectId) {
    projectId = process.env.GCLOUD_PROJECT || process.env.GCP_PROJECT;
    console.log("Using project from environment:", projectId);
  }

  // 硬编码项目 ID 用于测试（用户确认的项目 ID）
  if (!projectId) {
    projectId = "my-ai-video-key-id";
    console.log("Using hardcoded project ID for testing");
  }

  if (!projectId && !apiKey) {
    console.warn("GOOGLE_PROJECT_ID not set, attempting to use gcloud ADC...");
  }

  console.log("Initializing Vertex AI client...");
  console.log("Project ID:", projectId);
  console.log("Location:", location);

  // Initialize Vertex AI
  const vertexAI = new VertexAI({
    project: projectId,
    location: location,
  });

  // Model configuration
  const modelName = "veo-3.1-generate-001";

  // Map resolution to output quality
  const outputQuality = resolution === "4k" ? "quality" : "standard";

  const generativeModel = vertexAI.preview.getGenerativeModel({
    model: modelName,
  });

  // Build the request with text prompt only (no image)
  const request = {
    prompt: prompt,
    videoSpecs: {
      format: "mp4",
      duration: `${duration}s`,
      aspectRatio: aspectRatio,
      resolution: resolution,
      outputQuality: outputQuality,
    },
  };

  console.log("Sending video generation request to Veo 3.1...");
  console.log("Prompt:", prompt);

  try {
    // Start the video generation
    const [response] = await generativeModel.generateContent(request);
    
    // Handle different response types
    if (!response) {
      throw new Error("Empty response from Veo API");
    }

    // Check if there's a video in the response
    const videoData = response.candidates?.[0]?.content?.parts?.[0];
    
    if (videoData?.video) {
      console.log("Video generated successfully!");
      // The video data contains the URI
      const videoUri = videoData.video.uri || videoData.video.uri;
      console.log("Video URI:", videoUri);
      return videoUri;
    }

    // If no immediate video, check for operation
    // Veo uses long-running operations, so we might need to poll
    const operationName = response.videoOperation?.name;
    
    if (operationName) {
      console.log("Video generation operation started:", operationName);
      
      // Poll for the operation to complete
      const maxAttempts = 120; // 10 minutes max (5 seconds per attempt)
      const pollInterval = 5000; // 5 seconds

      for (let attempt = 0; attempt < maxAttempts; attempt++) {
        await new Promise((resolve) => setTimeout(resolve, pollInterval));
        
        const operation = await getVideoOperation(vertexAI, operationName, location);
        
        if (operation.done) {
          console.log("Video generation completed!");
          
          // Try to get the video URI from the operation response
          const result = operation.response as any;
          if (result?.generatedVideos?.[0]?.video?.uri) {
            return result.generatedVideos[0].video.uri;
          }
          
          // Alternative: try to download the video
          if (result?.generatedVideos?.[0]?.video) {
            // For now, return a placeholder - the actual download would need more handling
            return "video_generated";
          }
          
          throw new Error("Video operation completed but no video URI found");
        }
        
        console.log(`Waiting for video... (attempt ${attempt + 1}/${maxAttempts})`);
      }
      
      throw new Error("Video generation timed out");
    }

    // Log the full response for debugging
    console.log("Full response:", JSON.stringify(response, null, 2));
    throw new Error("Unexpected response format from Veo API");

  } catch (error: any) {
    console.error("Veo 3.1 API Error:", error);
    
    // Check for specific error types
    if (error.message?.includes("401") || error.message?.includes("authentication")) {
      throw new Error("Authentication failed. Please check your GOOGLE_PROJECT_ID and credentials.");
    }
    
    if (error.message?.includes("403") || error.message?.includes("permission")) {
      throw new Error("Permission denied. Please check your Google Cloud permissions.");
    }
    
    if (error.message?.includes("quota") || error.message?.includes("rate limit")) {
      throw new Error("Rate limit or quota exceeded. Please try again later.");
    }
    
    throw error;
  }
}

export async function getVideoStatus(operationName: string): Promise<any> {
  const projectId = process.env.GOOGLE_PROJECT_ID;
  const location = process.env.GOOGLE_LOCATION || "us-central1";

  if (!projectId) {
    throw new Error("GOOGLE_PROJECT_ID is not configured");
  }

  const vertexAI = new VertexAI({
    projectId: projectId,
    location: location,
  });

  return await getVideoOperation(vertexAI, operationName, location);
}
